issues.body:
I was created the flutter widget with focus node and handle the keyboard(up, down, right, left arrow) interaction. but framework removes the focus when outside the widget have any interactional widget(button).

Eg., In the below sample have the custom widget for handle focus through keyboard and it is not working well in desktop platform

## Steps to Reproduce

1. Run the sample with below added code
2. Tap to request the focus to widget
3. Press multiple(3 to 4) times right arrow and press 2 times down arrow
4. Press up arrow to reproduce the issue


<details>
<summary>code sample</summary>

```dart

void main() {
  return runApp(
      MaterialApp(
    home: Scaffold(
      appBar: AppBar(
        title: Text('Demo'),
        leading: RawMaterialButton(
          child: Text('DemoButton'),
          onPressed: () {
            print('Pressed1');
          },
        ),
      ),
      body: CustomContainer(),
    ),
  )
      );
}

class CustomContainer extends StatefulWidget {
  @override
  _CustomContainerState createState() => _CustomContainerState();
}

class _CustomContainerState extends State<CustomContainer> {
  FocusNode _focusNode;
  int _selectedIndex = -1;

  @override
  void initState() {
    _focusNode = FocusNode();
    _selectedIndex = -1;
    super.initState();
  }

  @override
  Widget build(BuildContext context) {
    return Container(
        child: GestureDetector(
            onTap: () {
              _focusNode.requestFocus();
            },
            child: RawKeyboardListener(
                focusNode: _focusNode,
                onKey: (RawKeyEvent event) {
                  if (event.runtimeType != RawKeyDownEvent) {
                    return;
                  }

                  if (_selectedIndex == -1) {
                    setState(() {
                      _selectedIndex = 0;
                    });
                  } else if (event.logicalKey ==
                      LogicalKeyboardKey.arrowRight) {
                    if ((_selectedIndex + 1) % 10 == 0) {
                      return;
                    }

                    setState(() {
                      _selectedIndex = _selectedIndex + 1;
                    });
                  } else if (event.logicalKey == LogicalKeyboardKey.arrowLeft) {
                    if (_selectedIndex % 10 == 0) {
                      return;
                    }

                    setState(() {
                      _selectedIndex = _selectedIndex - 1;
                    });
                  } else if (event.logicalKey == LogicalKeyboardKey.arrowUp) {
                    if (_selectedIndex - 10 < 0) {
                      return;
                    }

                    setState(() {
                      _selectedIndex = _selectedIndex - 10;
                    });
                  } else if (event.logicalKey == LogicalKeyboardKey.arrowDown) {
                    if (_selectedIndex + 10 >= 50) {
                      return;
                    }

                    setState(() {
                      _selectedIndex = _selectedIndex + 10;
                    });
                  }
                },
                child: GridView.count(
                  crossAxisCount: 10,
                  children: List.generate(50, (index) {
                    return Container(
                      height: 20,
                      color: _selectedIndex == index ? Colors.red : null,
                      child: Text(
                        'Item $index',
                        style: Theme.of(context).textTheme.headline5,
                      ),
                    );
                  }),
                ))));
  }
}
