            SizeTransition(
              sizeFactor: _controller,
              axisAlignment: 1.0,
              child: TextFormField(
                initialValue: 'Hello World!',
                decoration: InputDecoration(
                  border: OutlineInputBorder(),
                  labelText: 'Label',
                  floatingLabelStyle: TextStyle(fontSize: 28),
                  labelStyle: TextStyle(fontSize: 28),
