issues.body:
### Steps to reproduce

flutter create badscroll --platforms=web
add a view embedded in a div
add SingleChildScrollView with Columns of TextFormField entries
Scroll while the mouse pointer is over the text fields

Notes:
```
setting the text field to disable results in proper scrolling
              child: TextFormField(
                initialValue: "Text",
                enabled: false,
              ),
```


setting scrollPhysics to never doesn't help
                scrollPhysics: NeverScrollableScrollPhysics(),




### Expected results

The main web page should not scroll/bounce around
Only the flutter app/div should scroll

### Actual results

The page bounces around and the flutter div gets scrolled away

### Code sample

<details open><summary>Code sample</summary>


### main.dart

```dart
import 'package:flutter/material.dart';

import 'multi_view_app.dart';

void main() {
  runWidget(
    MultiViewApp(
      viewBuilder: (BuildContext context) => const MyApp(),
    ),
  );
}

class MyApp extends StatelessWidget {
  const MyApp({super.key});
  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      title: 'Flutter Demo',
      theme: ThemeData(
        colorScheme: ColorScheme.fromSeed(seedColor: Colors.deepPurple),
      ),
      home: const MyHomePage(title: 'Flutter Demo Home Page'),
    );
  }
}

class MyHomePage extends StatefulWidget {
  const MyHomePage({super.key, required this.title});
  final String title;
  @override
  State<MyHomePage> createState() => _MyHomePageState();
}

class _MyHomePageState extends State<MyHomePage> {
  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      builder: (context, child) {
        var widgets = <Widget>[];
        for ( var i = 0; i < 50; i++) {
          var w = SizedBox(
            width: 200,
            height: 100,
            child: TextFormField(
              initialValue: "Text",
              enabled: true,
            ),
          );
          widgets.add(w);
        }
        return Scaffold(
          body: Overlay(
              initialEntries: [
                OverlayEntry(builder: (context) {
                  return SingleChildScrollView(
                    child: Center(
                      child: Column(
                        mainAxisAlignment: MainAxisAlignment.center,
                        children: widgets,
                      ),
                    ),
                );
              })
              ]
          ),
        );
      },
    );
  }
}

```

### multi_view_app.dart

```dart
import 'dart:ui' show FlutterView;
import 'package:flutter/widgets.dart';

/// Calls [viewBuilder] for every view added to the app to obtain the widget to
/// render into that view. The current view can be looked up with [View.of].
class MultiViewApp extends StatefulWidget {
  const MultiViewApp({super.key, required this.viewBuilder});

  final WidgetBuilder viewBuilder;

  @override
  State<MultiViewApp> createState() => _MultiViewAppState();
}

class _MultiViewAppState extends State<MultiViewApp> with WidgetsBindingObserver {
  @override
  void initState() {
    super.initState();
    WidgetsBinding.instance.addObserver(this);
    _updateViews();
  }

  @override
  void didUpdateWidget(MultiViewApp oldWidget) {
    super.didUpdateWidget(oldWidget);
    // Need to re-evaluate the viewBuilder callback for all views.
    _views.clear();
    _updateViews();
  }

  @override
  void didChangeMetrics() {
    _updateViews();
  }

  Map<Object, Widget> _views = <Object, Widget>{};

  void _updateViews() {
    final Map<Object, Widget> newViews = <Object, Widget>{};
    for (final FlutterView view in WidgetsBinding.instance.platformDispatcher.views) {
      final Widget viewWidget = _views[view.viewId] ?? _createViewWidget(view);
      newViews[view.viewId] = viewWidget;
    }
    setState(() {
      _views = newViews;
    });
  }

  Widget _createViewWidget(FlutterView view) {
    return View(
      view: view,
      child: Builder(
        builder: widget.viewBuilder,
      ),
    );
  }

  @override
  void dispose() {
    WidgetsBinding.instance.removeObserver(this);
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    return ViewCollection(views: _views.values.toList(growable: false));
  }
}
```

