If you check the main.dart.txt file, it contains the very minimum to reproduce this issue. In it is two methods one is called onChangedWithIssue and onChangeWithoutIssue. The general fix is forcing the TextEditController to unfocus by calling its FocusNode before doing the change, making your changes, and then calling focus back on the TextEditController from its FocusNode.

```
void onValueChangeWithoutIssue() {
    _focusNode.unfocus();
    _controller.clear();
    setState(() {});
    WidgetsBinding.instance.addPostFrameCallback((ts)
    =>_focusNode.requestFocus());
  }
```

Normally I would not consider doing this as necessary. It has something to do specifically with Linux and Windows way of handling korean input in flutter.

 > @jkrogers9862 Can you please share the idea of your workaround? I have been thinking about switching to RN because of this.

For those, who needs a temporary solution

```dart
import 'package:flutter/material.dart';
import 'package:flutter/services.dart';
import 'package:pasteboard/pasteboard.dart';

extension ClipboardCompatibility on Widget {
  makeClipboardCompatible(controller) {
    bool firstTime = true;
    return GestureDetector(
      child: KeyboardListener(
          focusNode: FocusNode(),
          onKeyEvent: (value) async {
            const logicalKey = "Control Left";
            const physicalKey = 94489280512;

            if (value is KeyDownEvent &&
                value.logicalKey.keyLabel == logicalKey &&
                value.physicalKey.usbHidUsage == physicalKey) {
              if (firstTime) {
                // logger.e("Run");
                final text = await Pasteboard.text;

                if (controller.text.isEmpty) {
                  controller.text = text ?? "";
                } else {
                  controller.text += " $text";
                }
                firstTime = false;

                Future.delayed(
                  const Duration(milliseconds: 500),
                  () {
                    firstTime = true;
                  },
                );
              }
            }
          },
          child: this),
    );
  }
}

```

The key data sent from flutter engine is incorrect, it looks like there is no way to fix it outside. But we can intercept the event and correct the error, which can be a good temporary solution.

1. Create a injection file.
```dart
import 'dart:ui';

class WindowsInjector {

  static WindowsInjector get instance => _instance;
  static final WindowsInjector _instance = WindowsInjector._();

  bool _startInjectKeyData = false;

  WindowsInjector._();

  void injectKeyData() {
    // Wait a second to inject KeyData callback
    Future.delayed(const Duration(seconds: 1), _injectkeyData);
  }

  void _injectkeyData() {
    final KeyDataCallback? callback = PlatformDispatcher.instance.onKeyData;
    if (callback == null) {
      // Failed to get the built-in callback, skip the injection.
      return;
    }
    PlatformDispatcher.instance.onKeyData = (data) {
      if (!_startInjectKeyData && data.physical == 0x1600000000 && data.logical == 0x200000100 && data.type == KeyEventType.down && !data.synthesized) {
        // Change to Control Left key down event.
        data = KeyData(
          timeStamp: data.timeStamp,
          type: KeyEventType.down,
          physical: 0x700e0,
          logical: 0x200000100,
          character: null,
          synthesized: false,
        );
        _startInjectKeyData = true;
      } else if (_startInjectKeyData && data.physical == 0 && data.logical == 0 && data.type == KeyEventType.down && !data.synthesized) {
        return true;
      } else if (_startInjectKeyData && data.physical == 0x1600000000 && data.logical == 0x200000100 && data.type == KeyEventType.up && !data.synthesized) {
        // Change to V key down event.
        data = KeyData(
          timeStamp: data.timeStamp,
          type: KeyEventType.down,
          physical: 0x70019,
          logical: 0x76,
          character: null,
          synthesized: false,
        );
      } else if (_startInjectKeyData && data.physical == 0x1600000000 && data.logical == 0x200000100 && data.type == KeyEventType.down && data.synthesized) {
        // Change to V key up event.
        data = KeyData(
          timeStamp: data.timeStamp,
          type: KeyEventType.up,
          physical: 0x70019,
          logical: 0x76,
          character: null,
          synthesized: false,
        );
      } else if (_startInjectKeyData && data.physical == 0x1600000000 && data.logical == 0x200000100 && data.type == KeyEventType.up && data.synthesized) {
        // Change to Control Left key up event.
        data = KeyData(
          timeStamp: data.timeStamp,
          type: KeyEventType.up,
          physical: 0x700e0,
          logical: 0x200000100,
          character: null,
          synthesized: false,
        );
        _startInjectKeyData = false;
      } else {
        _startInjectKeyData = false;
      }
      return callback(data);
    };
  }

}
```

2. Call the injector in the `main.dart`.
```dart
if (Platform.isWindows) {
  WindowsInjector.instance.injectKeyData();
}
```

3. The clipboard history works now.

